const body = $input.first().json.body || $input.first().json;
const { action, username, password, filename, content } = body;

if (!username || !password) {
  return [{ json: { success: false, error: 'Identifiants manquants' } }];
}

const baseUrl = `https://nuage.apps.education.fr/remote.php/dav/files/${encodeURIComponent(username)}/mentoria/`;
const manifestUrl = baseUrl + 'manifest.json';
const auth = 'Basic ' + Buffer.from(`${username}:${password}`).toString('base64');

const doRequest = async (method, url, bodyData) => {
  const opts = {
    method, url,
    headers: { 'Authorization': auth },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    disableFollowRedirect: true
  };
  if (bodyData !== undefined) {
    opts.body = bodyData;
    opts.headers['Content-Type'] = 'application/octet-stream';
  }
  return await this.helpers.httpRequest(opts);
};

const davGet = (url) => doRequest('GET', url);
const davPut = (url, data) => doRequest('PUT', url, data);
const davDelete = (url) => doRequest('DELETE', url);

const tryParseManifest = (r) => {
  if (r.statusCode !== 200) return null;
  try {
    const parsed = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
    return Array.isArray(parsed) ? parsed : null;
  } catch { return null; }
};

const getManifest = async () => {
  const r = await davGet(manifestUrl);
  return tryParseManifest(r) || [];
};

const saveManifest = async (list) => {
  const r = await davPut(manifestUrl, JSON.stringify(list));
  if (r.statusCode >= 400) throw new Error('Échec sauvegarde manifest (code ' + r.statusCode + ')');
};

try {

  // ── TEST ──
  if (action === 'test') {
    const debug = {};

    // 1. Vérif identifiants OCS
    const ocsRes = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://nuage.apps.education.fr/ocs/v1.php/cloud/user?format=json',
      headers: { 'Authorization': auth, 'OCS-APIREQUEST': 'true' },
      returnFullResponse: true, ignoreHttpStatusErrors: true
    });
    debug.ocs_status = ocsRes.statusCode;
    if (ocsRes.statusCode === 401 || ocsRes.statusCode === 403) {
      return [{ json: { success: false, error: 'Identifiants invalides — vérifiez votre mot de passe d\'application.', debug } }];
    }
    if (ocsRes.statusCode !== 200) {
      return [{ json: { success: false, error: 'Erreur OCS: ' + ocsRes.statusCode, debug } }];
    }

    // 2. Test PUT direct sur un fichier de test dans la racine (hors mentoria)
    //    pour vérifier si PUT fonctionne du tout
    const testPutUrl = `https://nuage.apps.education.fr/remote.php/dav/files/${encodeURIComponent(username)}/_mentoria_test.txt`;
    const testPut = await doRequest('PUT', testPutUrl, 'test');
    debug.test_put_root_status = testPut.statusCode;
    debug.test_put_root_body = (typeof testPut.body === 'string' ? testPut.body : JSON.stringify(testPut.body)).substring(0, 100);

    // 3. Test GET manifest
    const getRes = await davGet(manifestUrl);
    debug.get_manifest_status = getRes.statusCode;
    debug.get_manifest_body = (typeof getRes.body === 'string' ? getRes.body : JSON.stringify(getRes.body)).substring(0, 80);
    const manifestValid = tryParseManifest(getRes) !== null;
    debug.manifest_valid = manifestValid;

    // 4. Test PUT manifest si invalide
    if (!manifestValid) {
      const putRes = await davPut(manifestUrl, '[]');
      debug.put_manifest_status = putRes.statusCode;
      debug.put_manifest_body = (typeof putRes.body === 'string' ? putRes.body : JSON.stringify(putRes.body)).substring(0, 100);
      if (putRes.statusCode >= 400) {
        return [{ json: { success: false, error: 'Impossible d\'écrire dans le dossier mentoria (code ' + putRes.statusCode + ').', debug } }];
      }
    }

    return [{ json: { success: true, action: 'test', debug } }];
  }

  // ── LIST ──
  if (action === 'list') {
    const manifest = await getManifest();
    return [{ json: { success: true, files: manifest.map(n => ({ name: n })) } }];
  }

  // ── READ ──
  if (action === 'read') {
    const r = await davGet(baseUrl + encodeURIComponent(filename));
    if (r.statusCode === 404) return [{ json: { success: false, error: 'Fichier introuvable' } }];
    if (r.statusCode === 401) return [{ json: { success: false, error: 'Session expirée — reconnectez-vous' } }];
    if (r.statusCode >= 400) return [{ json: { success: false, error: 'Erreur lecture (code ' + r.statusCode + ')' } }];
    try {
      const parsed = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
      return [{ json: { success: true, content: parsed } }];
    } catch(e) {
      return [{ json: { success: false, error: 'Fichier corrompu : ' + e.message } }];
    }
  }

  // ── WRITE ──
  if (action === 'write') {
    const data = typeof content === 'string' ? content : JSON.stringify(content, null, 2);
    const r = await davPut(baseUrl + encodeURIComponent(filename), data);
    if (r.statusCode === 404 || r.statusCode === 409) {
      return [{ json: { success: false, error: 'Dossier mentoria introuvable. Reconnectez-vous.' } }];
    }
    if (r.statusCode === 401) return [{ json: { success: false, error: 'Session expirée — reconnectez-vous' } }];
    if (r.statusCode >= 400) return [{ json: { success: false, error: 'Erreur écriture (code ' + r.statusCode + ')' } }];
    const manifest = await getManifest();
    if (!manifest.includes(filename)) {
      manifest.push(filename);
      await saveManifest(manifest);
    }
    return [{ json: { success: true, action: 'write' } }];
  }

  // ── DELETE ──
  if (action === 'delete') {
    await davDelete(baseUrl + encodeURIComponent(filename));
    const manifest = await getManifest();
    await saveManifest(manifest.filter(n => n !== filename));
    return [{ json: { success: true, action: 'delete' } }];
  }

  return [{ json: { success: false, error: 'Action inconnue : ' + action } }];

} catch(e) {
  return [{ json: { success: false, error: e.message } }];
}
